INSERT INTO chat_messages (id, conversation_id, role, content, message_type, metadata, created_at) VALUES
('msg-001', 'conv-001', 'user', 'What is the recommended HbA1c target for my patient Ramesh Kumar, age 58, with diabetes and hypertension?', 'text', NULL, '2026-03-15 09:00:00'),
('msg-002', 'conv-001', 'assistant', 'For Ramesh Kumar (58 years, Type 2 DM with hypertension), the recommended HbA1c target is <7.0% (53 mmol/mol) as per ADA/ICMR guidelines. Given his hypertension comorbidity, tight glycemic control is important but hypoglycemia should be avoided. Consider: 1) Metformin as first-line if eGFR >30 2) SGLT2 inhibitor (Dapagliflozin/Empagliflozin) for dual cardio-renal benefit 3) BP target <130/80 mmHg 4) Statin therapy for cardiovascular risk reduction.', 'text', '{"references": ["ADA Standards 2026", "ICMR Guidelines"]}', '2026-03-15 09:01:00'),
('msg-003', 'conv-001', 'user', 'His current HbA1c is 8.2%. He is on Metformin 1000mg BD. Should I add an SGLT2 inhibitor?', 'text', NULL, '2026-03-15 09:05:00'),
('msg-004', 'conv-001', 'assistant', 'Yes, adding an SGLT2 inhibitor is strongly recommended given: 1) HbA1c 8.2% is above target on Metformin alone 2) Co-existing hypertension - SGLT2i provides BP reduction of 3-5 mmHg 3) Cardiovascular protection (EMPA-REG, DAPA-HF trials). Recommended options: - Dapagliflozin 10mg OD or Empagliflozin 10mg OD. Before starting, check: eGFR (should be >20 for Dapa, >20 for Empa), urinalysis for UTI, and counsel about genital mycotic infections. Monitor renal function at 1 month.', 'text', '{"references": ["EMPA-REG OUTCOME", "DAPA-HF Trial"]}', '2026-03-15 09:06:00'),
('msg-005', 'conv-001', 'user', 'What about adding a DPP-4 inhibitor instead?', 'text', NULL, '2026-03-15 09:10:00'),
('msg-006', 'conv-001', 'assistant', 'DPP-4 inhibitors (Sitagliptin, Vildagliptin) are an option but SGLT2 inhibitors are preferred in this case because: 1) DPP-4i are weight-neutral while SGLT2i promote weight loss (2-3 kg) 2) DPP-4i lack proven cardiovascular benefit (TECOS, EXAMINE trials showed non-inferiority only) 3) SGLT2i reduce heart failure hospitalization by 35% 4) SGLT2i provide additional BP lowering. DPP-4i would be appropriate if: patient has recurrent UTIs/genital infections, eGFR <20, or cannot tolerate SGLT2i. The HbA1c lowering is similar (0.5-0.8% for both).', 'text', NULL, '2026-03-15 09:11:00'),
('msg-007', 'conv-001', 'user', 'Good points. I will start Dapagliflozin 10mg. What monitoring plan do you suggest?', 'text', NULL, '2026-03-15 09:15:00'),
('msg-008', 'conv-001', 'assistant', 'Monitoring plan for Ramesh Kumar after starting Dapagliflozin: Week 2: Phone follow-up for symptoms (polyuria, dizziness, genital itching). Month 1: Serum creatinine, eGFR, electrolytes (watch for euglycemic DKA signs). Month 3: HbA1c recheck (target reduction 0.5-0.8%), fasting glucose, renal panel, BP review. Month 6: Comprehensive review - HbA1c, lipid panel, urine ACR, eGFR, fundoscopy. Ongoing: Blood glucose monitoring, weight tracking, BP log. Counsel patient to maintain hydration, report any unusual symptoms.', 'text', NULL, '2026-03-15 09:16:00'),
('msg-009', 'conv-001', 'user', 'Also check his Ayushman Bharat coverage for Dapagliflozin availability.', 'text', NULL, '2026-03-15 09:20:00'),
('msg-010', 'conv-001', 'assistant', 'Under Ayushman Bharat PMJAY, Dapagliflozin is available in the National List of Essential Medicines (NLEM) 2022 update. Key points: 1) Generic Dapagliflozin 10mg is covered under AB-PMJAY essential drug list 2) Cost: approximately Rs 8-12 per tablet (generic) vs Rs 35-45 (branded) 3) Available at AB-PMJAY empanelled hospitals and Jan Aushadhi stores 4) Patient can also access through PM Bhartiya Janaushadhi Pariyojana at subsidized rates. Ensure prescription mentions generic name for coverage compliance.', 'text', '{"references": ["NLEM 2022", "AB-PMJAY Drug Formulary"]}', '2026-03-15 09:21:00'),
('msg-011', 'conv-002', 'user', 'Need a comprehensive follow-up plan for Suresh Babu, 62M, post-CABG 2022, now presenting with reduced exercise tolerance.', 'text', NULL, '2026-03-16 10:00:00'),
('msg-012', 'conv-002', 'assistant', 'Post-CABG Follow-up Plan for Suresh Babu (62M, CABG 2022): Immediate Assessment: 1) 2D Echocardiography - assess LV function, wall motion, graft patency indicators 2) TMT/Stress Echo - evaluate exercise capacity and ischemia 3) NT-proBNP level - rule out heart failure progression 4) CBC, RFT, LFT, Lipid panel, HbA1c 5) ECG - compare with previous. Cardiac Rehabilitation: Phase III program - supervised exercise 3x/week, target 150 min moderate activity/week. Medications to verify: Aspirin 75mg, Clopidogrel (if within 1 year), Statin (Atorvastatin 40-80mg), Beta-blocker, ACE inhibitor/ARB.', 'text', NULL, '2026-03-16 10:02:00'),
('msg-013', 'conv-002', 'user', 'His echo shows EF 38% reduced from 45% last year. What should I consider?', 'text', NULL, '2026-03-16 10:10:00'),
('msg-014', 'conv-002', 'assistant', 'EF decline from 45% to 38% is concerning and suggests progressive LV dysfunction. Differential considerations: 1) Graft occlusion - CT coronary angiography or conventional angiogram indicated 2) Progressive cardiomyopathy 3) Valvular pathology development 4) Medication non-compliance. Recommended actions: Urgent CT coronary angiogram to assess graft patency. Start/optimize GDMT for HFrEF: Sacubitril/Valsartan (ARNI) instead of ACE-i, Carvedilol/Bisoprolol titrate to max tolerated, Spironolactone 25mg, Dapagliflozin 10mg (if not already on). Consider CRT-D if EF remains <35% after 3 months of optimal medical therapy.', 'text', '{"references": ["ESC HF Guidelines 2023", "ACC/AHA CABG Guidelines"]}', '2026-03-16 10:12:00'),
('msg-015', 'conv-002', 'user', 'The ECHS coverage - will CT angiogram be covered?', 'text', NULL, '2026-03-16 10:20:00'),
('msg-016', 'conv-002', 'assistant', 'Yes, CT Coronary Angiography is covered under ECHS for post-CABG patients. Details: 1) CT Coronary Angiography - covered under ECHS at empanelled hospitals, no separate pre-authorization needed for post-CABG surveillance 2) If conventional angiogram is needed subsequently - covered with pre-authorization 3) If re-intervention (PCI/redo CABG) is required - covered with mandatory pre-authorization from ECHS Regional Center 4) Cardiac rehabilitation program - covered for up to 36 sessions/year. Ensure referral letter mentions post-CABG EF decline as clinical indication. ECHS card and referral from polyclinic required.', 'text', NULL, '2026-03-16 10:22:00'),
('msg-017', 'conv-002', 'user', 'Also, should we consider cardiac MRI?', 'text', NULL, '2026-03-16 10:30:00'),
('msg-018', 'conv-002', 'assistant', 'Cardiac MRI is an excellent choice for Suresh Babu. Benefits in this case: 1) Myocardial viability assessment - Late Gadolinium Enhancement (LGE) to identify viable vs scarred myocardium, crucial for deciding revascularization benefit 2) Accurate EF measurement - MRI is gold standard for LV volumes and EF 3) Stress perfusion MRI - can detect ischemia with high sensitivity (89%) and specificity (87%) 4) No radiation exposure compared to CT angiogram. ECHS Coverage: Cardiac MRI is covered under ECHS at empanelled tertiary centers. Pre-authorization may be required. Turnaround time typically 5-7 working days for approval. Contraindication check: Ensure no MRI-incompatible metallic implants from CABG (modern sternal wires are usually MRI-safe).', 'text', NULL, '2026-03-16 10:32:00'),
('msg-019', 'conv-003', 'user', 'Review the current medication list for Arun Krishnan, 70M COPD Stage 3. He is on Tiotropium 18mcg, Formoterol 12mcg BD, and Budesonide 400mcg BD inhaler.', 'text', NULL, '2026-03-17 11:00:00'),
('msg-020', 'conv-003', 'assistant', 'Medication Review for Arun Krishnan (70M, COPD GOLD Stage 3/Severe): Current regimen is LAMA + LABA + ICS (Triple therapy), which is appropriate for GOLD Group E (formerly D) with frequent exacerbations. Assessment: 1) Tiotropium 18mcg OD via HandiHaler - appropriate LAMA choice 2) Formoterol 12mcg BD - appropriate LABA 3) Budesonide 400mcg BD - consider if eosinophil count >300, otherwise ICS may be de-escalated. Suggestions: Consider switching to single triple inhaler (Fluticasone/Umeclidinium/Vilanterol or Beclomethasone/Formoterol/Glycopyrronium) for better adherence. Add: Roflumilast 500mcg OD if FEV1 <50% with frequent exacerbations. Ensure: Pneumococcal and influenza vaccination, pulmonary rehabilitation referral, home nebulizer if needed.', 'text', '{"references": ["GOLD 2026 Report"]}', '2026-03-17 11:02:00'),
('msg-021', 'conv-003', 'user', 'He has had 3 exacerbations in the last year. Eosinophil count is 180. Should I continue the ICS?', 'text', NULL, '2026-03-17 11:10:00'),
('msg-022', 'conv-003', 'assistant', 'With eosinophil count 180 (<300) and 3 exacerbations/year, the approach should be: Consider ICS de-escalation: Per GOLD 2026, ICS withdrawal can be considered when blood eosinophils <300 AND no frequent exacerbations attributed to eosinophilic inflammation. However, given 3 exacerbations/year: 1) Do NOT abruptly stop ICS - taper gradually 2) Add Roflumilast 500mcg OD (PDE4 inhibitor) - reduces exacerbations by 15-20% in severe COPD 3) Check sputum culture for chronic bacterial colonization 4) Consider Azithromycin 250mg 3x/week (prophylactic) if non-smoker with continued exacerbations. Recommended: Maintain ICS for now given high exacerbation frequency, add Roflumilast, reassess in 3 months. If eosinophils consistently <100 on repeat, then consider ICS step-down.', 'text', NULL, '2026-03-17 11:12:00'),
('msg-023', 'conv-003', 'user', 'What inhaler technique assessment should I do?', 'text', NULL, '2026-03-17 11:20:00'),
('msg-024', 'conv-003', 'assistant', 'Inhaler Technique Assessment for Arun Krishnan: Checklist for HandiHaler (Tiotropium): 1) Opens device correctly 2) Inserts capsule properly 3) Closes mouthpiece with click 4) Exhales fully away from device 5) Seals lips around mouthpiece 6) Inhales slowly and deeply 7) Holds breath 10 seconds 8) Checks capsule is empty (re-inhale if needed). Common errors in elderly patients: Poor inspiratory flow (<20 L/min needed), not piercing capsule fully, exhaling into device. For MDI (Budesonide): Consider switching to DPI or adding spacer if coordination is poor. Assessment tools: Use In-Check DIAL to measure inspiratory flow. If flow <30 L/min, consider nebulized therapy. Document technique score in patient record. Schedule nurse educator follow-up every visit.', 'text', NULL, '2026-03-17 11:22:00'),
('msg-025', 'conv-004', 'user', 'How do I process a claim that was rejected due to incomplete documentation? The claim is for an Ayushman Bharat patient.', 'text', NULL, '2026-03-18 09:30:00'),
('msg-026', 'conv-004', 'assistant', 'To process a rejected Ayushman Bharat claim due to incomplete documentation: Step 1: Identify missing documents from the rejection letter on the TMS portal. Common missing items: treatment summary, discharge summary, investigation reports, pre-authorization reference. Step 2: Collect the required documents from the treating department. Ensure all documents have hospital stamp and authorized signature. Step 3: In the AyushmanLife system, go to Claims > find the claim > click Resubmit. Upload the additional documents and add a note explaining the resubmission. Step 4: The claim will be resubmitted to SHA (State Health Agency) via the TMS portal. Typical reprocessing time: 7-15 working days. Step 5: Track status in Claims dashboard. If rejected again, file a formal grievance through the AB-PMJAY grievance portal within 30 days.', 'text', NULL, '2026-03-18 09:32:00'),
('msg-027', 'conv-004', 'user', 'What documents are mandatory for an AB-PMJAY surgical claim?', 'text', NULL, '2026-03-18 09:40:00'),
('msg-028', 'conv-004', 'assistant', 'Mandatory documents for AB-PMJAY surgical claims: Pre-Authorization Phase: 1) Patient photo with AB card 2) Aadhaar verification (biometric/OTP) 3) Clinical summary with diagnosis 4) Investigation reports supporting surgery 5) Pre-authorization form signed by treating doctor. Post-Surgery/Claim Phase: 1) Detailed discharge summary 2) Operative notes with surgeon signature 3) Anesthesia record 4) Investigation reports (pre-op and post-op) 5) Histopathology report (if applicable) 6) Implant details with invoice and sticker (if applicable) 7) Medicine and consumable bills 8) Patient consent forms 9) Photographs (pre-op, intra-op, post-op for specific packages) 10) ICU monitoring charts (if ICU stay). Important: All documents must be uploaded within 10 days of discharge. Missing any can delay payment by 30-60 days.', 'text', '{"references": ["AB-PMJAY Claims Manual 2025"]}', '2026-03-18 09:42:00'),
('msg-029', 'conv-005', 'user', 'What dietary recommendations should I give Savitri Mishra, 67F, CKD Stage 2 with diabetes? Her creatinine is 1.8 and potassium 5.1.', 'text', NULL, '2026-03-18 14:00:00'),
('msg-030', 'conv-005', 'assistant', 'Dietary recommendations for Savitri Mishra (67F, CKD Stage 2, DM, Cr 1.8, K+ 5.1): Protein: 0.8 g/kg/day (moderate restriction for CKD 2 with diabetes). For a 60kg woman, approximately 48g protein/day. Focus on high biological value protein (egg whites, fish). Potassium (K+ 5.1 - mildly elevated): Restrict to 2000mg/day. Avoid: bananas, oranges, coconut water, potatoes (if not leached), spinach, tomatoes. Allow: apples, pears, rice, wheat. Teach double-boiling technique for vegetables. Sodium: Restrict to 2g/day (no added salt). Avoid pickles, papads, processed foods. Phosphorus: Limit dairy to 1 serving/day, avoid colas and processed cheese. Carbohydrates: Complex carbs with low glycemic index - ragi, oats, whole wheat. Avoid refined sugar, white rice in excess. Fluids: No restriction at CKD Stage 2 unless edema present.', 'text', NULL, '2026-03-18 14:02:00'),
('msg-031', 'conv-005', 'user', 'She is vegetarian. How to ensure adequate protein?', 'text', NULL, '2026-03-18 14:10:00'),
('msg-032', 'conv-005', 'assistant', 'Vegetarian protein sources for CKD patient (target 48g/day): High biological value options: 1) Egg whites (if ovo-vegetarian) - 3.6g per egg white, low potassium/phosphorus 2) Paneer (cottage cheese) - 18g per 100g, but limit due to phosphorus 3) Soy products (tofu) - 8g per 100g, moderate potassium. Complementary proteins: Combine dal (lentils) with rice for complete amino acids. However, limit dal to 1 small bowl/day due to potassium and phosphorus. Good options: Moong dal (lower potassium than rajma/chana). Other sources: Quinoa, amaranth (rajgira). Indian meal plan example: Breakfast: 2 egg whites + 1 roti (12g protein). Lunch: Small bowl moong dal + rice + sabzi (15g). Snack: 50g paneer (9g). Dinner: 2 roti + sabzi + curd 100ml (12g). Total approximately 48g. Consider: Ketoanalogue supplements (Ketosteril) if protein-energy wasting develops.', 'text', NULL, '2026-03-18 14:12:00'),
('msg-033', 'conv-005', 'user', 'What about her Metformin intolerance? She had GI issues.', 'text', NULL, '2026-03-18 14:20:00'),
('msg-034', 'conv-005', 'assistant', 'For Savitri Mishra with Metformin GI intolerance in CKD Stage 2 (eGFR likely 60-89): Alternative glucose-lowering agents: First choice: Vildagliptin 50mg BD - well-tolerated, renal dose adjustment at lower eGFR, no GI side effects, available as affordable generic in India (Rs 8-12/tablet). Second choice: Empagliflozin 10mg OD - provides renal protection (EMPA-KIDNEY trial), mild weight loss, but monitor for UTI in elderly female. Caution: avoid if recurrent UTIs. Consider: Glimepiride 1-2mg OD if above insufficient, but risk of hypoglycemia in elderly with CKD. Use cautiously. Avoid: Full-dose Metformin (known intolerance), Pioglitazone (fluid retention risk with CKD). Metformin rechallenge option: Extended-release Metformin (Metformin SR/XR) 500mg with dinner may be tolerated. Start low, increase slowly. Success rate of XR formulation: 50-60% in patients intolerant to IR.', 'text', '{"references": ["KDIGO DM-CKD Guidelines 2022"]}', '2026-03-18 14:22:00'),
('msg-035', 'conv-006', 'user', 'Create a cardiac rehab plan for Dinesh Tiwari, 63M, post-stent with diabetes. He is sedentary and overweight.', 'text', NULL, '2026-03-19 09:00:00'),
('msg-036', 'conv-006', 'assistant', 'Cardiac Rehabilitation Plan for Dinesh Tiwari (63M, post-PCI with stent, DM, sedentary, overweight): Phase I (Hospital, already completed): Bed mobility and walking. Phase II (Outpatient, 12 weeks): Assessment: TMT/6-minute walk test baseline, body composition, flexibility test. Exercise prescription: Frequency: 3-5 sessions/week (supervised first 4 weeks, then home-based). Intensity: 40-60% of Heart Rate Reserve (HRR). RPE 11-13 (fairly light to somewhat hard). Mode: Walking, stationary cycling, light resistance training. Time: Start 20 min, progress to 45 min over 12 weeks. Warm-up 10 min, cool-down 10 min. Resistance training: Start week 3, major muscle groups 2x/week, low weight high reps. Weight target: Lose 5-7% body weight over 6 months. Diet: 1500-1800 kcal/day, Mediterranean-Indian fusion diet. Risk factor education: Smoking cessation (if applicable), stress management, medication adherence.', 'text', NULL, '2026-03-19 09:02:00'),
('msg-037', 'conv-006', 'user', 'What are the safety precautions given his stent?', 'text', NULL, '2026-03-19 09:15:00'),
('msg-038', 'conv-006', 'assistant', 'Safety precautions for exercise post-stent (Dinesh Tiwari): Absolute contraindications to exercise: Unstable angina, uncontrolled arrhythmia, decompensated HF, severe aortic stenosis, acute systemic illness. Pre-exercise checklist: 1) Confirm dual antiplatelet therapy compliance (Aspirin + Ticagrelor/Clopidogrel) 2) Blood sugar 100-250 mg/dL before exercise (diabetes-specific) 3) No chest pain in previous 24 hours 4) BP <180/110 before starting. During exercise monitoring: ECG telemetry during supervised sessions (first 4 weeks). Stop exercise if: chest pain, dizziness, excessive dyspnea, BP drop >20 mmHg, blood sugar <70 mg/dL. Diabetic foot care: Check feet before and after exercise, proper footwear, no barefoot walking. Emergency: Keep GTN spray and glucose tablets available. Staff trained in BLS/ACLS. Defibrillator accessible in rehab area.', 'text', NULL, '2026-03-19 09:17:00'),
('msg-039', 'conv-006', 'user', 'Can he do yoga?', 'text', NULL, '2026-03-19 09:30:00'),
('msg-040', 'conv-006', 'assistant', 'Yes, yoga is beneficial and recommended for post-stent cardiac patients. Evidence-based benefits for Dinesh Tiwari: 1) Reduces stress and cortisol (lowers cardiac events by 15%) 2) Improves flexibility and balance (fall prevention in elderly) 3) Mild-moderate intensity suitable for cardiac rehab 4) Studies show yoga reduces HbA1c by 0.3-0.5% in diabetics 5) BP reduction of 5-8 mmHg reported. Recommended yoga practices: Pranayama: Anulom Vilom (alternate nostril breathing) - 10 min, Bhramari - 5 min. Avoid: Kapalbhati (can raise BP), forceful breathing. Asanas (gentle): Tadasana, Trikonasana, Sukhasana, Shavasana, Viparita Karani (legs up wall). Avoid: Inversions (Shirshasana), intense backbends, prolonged breath-holding. Meditation: 15-20 minutes daily. Start at week 4 of rehab, under trained yoga therapist initially. Certified cardiac yoga programs available at many Indian hospitals.', 'text', '{"references": ["INTERYOGA Trial", "Indian Heart Journal 2024"]}', '2026-03-19 09:32:00'),
('msg-041', 'conv-007', 'user', 'What is the correct protocol for IV cannula site assessment and rotation?', 'text', NULL, '2026-03-20 07:00:00'),
('msg-042', 'conv-007', 'assistant', 'IV Cannula Site Assessment and Rotation Protocol: Assessment frequency: Every 4 hours for peripheral IV sites, every shift change at minimum. VIP Score (Visual Infusion Phlebitis Score): 0 - IV site healthy (continue monitoring). 1 - Slight pain or redness near site (observe closely). 2 - Pain, redness, swelling at site (re-site cannula). 3 - Pain along vein path, induration (re-site and consider treatment). 4 - Advanced phlebitis/thrombophlebitis (re-site, inform doctor, initiate treatment). Rotation schedule: Replace peripheral IV cannula every 72-96 hours (as per INS Standards 2024). Earlier if VIP score >=2 or signs of infection. Documentation: Record in nursing notes - site, gauge, date of insertion, VIP score each assessment, date of planned rotation. Best practice: Use smallest gauge suitable (22G for most adults), secure with transparent dressing, label with date/time/initials.', 'text', NULL, '2026-03-20 07:02:00'),
('msg-043', 'conv-007', 'user', 'What about central line care?', 'text', NULL, '2026-03-20 07:10:00'),
('msg-044', 'conv-007', 'assistant', 'Central Line Care Bundle (CLABSI Prevention): Daily Assessment: 1) Check insertion site through transparent dressing 2) Assess for redness, swelling, drainage, tenderness 3) Check line patency and all connections secure 4) Verify daily necessity - prompt removal when no longer needed. Dressing changes: Transparent semi-permeable dressing every 7 days. Gauze dressing every 2 days. Change immediately if soiled, damp, or loose. Use 2% chlorhexidine in 70% alcohol for skin antisepsis. Hub and connection care: Scrub the hub with 70% alcohol for 15 seconds before each access. Allow 30 seconds drying time. Use needleless connectors, change every 7 days. Flushing: Pulsatile flush with 10ml normal saline before and after medication. Heparin lock per hospital protocol if intermittent use. Documentation: Record daily in CVC care checklist. Track line days for CLABSI surveillance.', 'text', '{"references": ["INS Standards 2024", "CDC CLABSI Prevention"]}', '2026-03-20 07:12:00'),
('msg-045', 'conv-008', 'user', 'What is the recommended follow-up protocol for Rekha Choudhary, post-mastectomy for Stage 2 breast cancer? She completed surgery 6 months ago.', 'text', NULL, '2026-03-20 10:00:00'),
('msg-046', 'conv-008', 'assistant', 'Follow-up protocol for Rekha Choudhary (50F, Stage 2 breast cancer, 6 months post-mastectomy, on Tamoxifen): Year 1-2 (current phase): Clinical examination every 3 months. Mammogram of opposite breast annually. CBC, LFT every 3 months (Tamoxifen monitoring). Tumor markers (CA 15-3, CEA) every 3 months (though utility debated). Bone density scan (DEXA) baseline and annually (Tamoxifen can affect bones in premenopausal women). Pelvic ultrasound annually (Tamoxifen endometrial monitoring). Year 3-5: Clinical exam every 6 months. Annual mammogram, DEXA, pelvic ultrasound. Tumor markers every 6 months. After Year 5: Annual clinical exam and mammogram lifelong. Consider switching to Aromatase Inhibitor if postmenopausal. Ongoing: Lymphedema screening, psychosocial support, physical rehabilitation, fertility counseling if relevant.', 'text', '{"references": ["NCCN Breast Cancer Surveillance 2025"]}', '2026-03-20 10:02:00'),
('msg-047', 'conv-008', 'user', 'She reports hot flashes and joint pain on Tamoxifen. Management?', 'text', NULL, '2026-03-20 10:15:00'),
('msg-048', 'conv-008', 'assistant', 'Management of Tamoxifen side effects for Rekha Choudhary: Hot flashes: 1) Lifestyle: Layer clothing, cool environment, avoid triggers (spicy food, hot beverages) 2) Non-hormonal medications: Venlafaxine 37.5-75mg OD (most evidence), or Gabapentin 300mg TDS 3) Clonidine 0.1mg BD (if hypertension coexists) 4) Yoga and mindfulness (evidence-based, 30% reduction) 5) Avoid: SSRIs like Paroxetine/Fluoxetine (CYP2D6 inhibitors reduce Tamoxifen efficacy). Joint pain (arthralgia): 1) Regular exercise - 30 min walking daily 2) Omega-3 fatty acids 1000mg OD 3) Calcium 1000mg + Vitamin D3 60,000 IU weekly 4) Paracetamol for pain (avoid NSAIDs long-term) 5) Physiotherapy referral 6) Acupuncture (moderate evidence). Important: Do NOT stop Tamoxifen without oncologist consultation. Side effects often improve after 3-6 months. Continue Tamoxifen for full 5-10 year course for maximum recurrence reduction benefit.', 'text', NULL, '2026-03-20 10:17:00'),
('msg-049', 'conv-008', 'user', 'Is her AB-PMJAY coverage still valid for follow-up oncology care?', 'text', NULL, '2026-03-20 10:30:00'),
('msg-050', 'conv-008', 'assistant', 'AB-PMJAY coverage for follow-up oncology care for Rekha Choudhary: Yes, coverage continues. Key details: 1) Follow-up consultations: Covered under AB-PMJAY for 1 year post-treatment as part of the cancer package 2) Investigations (mammogram, blood tests): Covered when linked to cancer follow-up, must be at empanelled hospital 3) Tamoxifen: Covered under the chemotherapy/hormonal therapy package for the prescribed duration 4) If recurrence: New package can be initiated with fresh pre-authorization 5) Reconstructive surgery: Covered under specific plastic surgery packages. Limitations: OPD consultations beyond the package period may not be covered. Encourage her to also enroll in the National Cancer Registry follow-up program. She should carry AB card and cancer treatment summary to every visit for seamless coverage verification.', 'text', '{"references": ["AB-PMJAY Oncology Package Guidelines"]}', '2026-03-20 10:32:00'),
('msg-051', 'conv-009', 'user', 'Ashok Pandey has a diabetic foot ulcer grade 2 (Wagner). What is the wound care protocol?', 'text', NULL, '2026-03-21 09:00:00'),
('msg-052', 'conv-009', 'assistant', 'Diabetic Foot Ulcer Management for Ashok Pandey (56M, Wagner Grade 2 - ulcer penetrating to tendon/capsule): Wound Assessment: Size, depth, undermining, tunneling. Document with photographs. Check peripheral pulses (ABI test). Assess neuropathy (monofilament, vibration). Wound Care Protocol: 1) Debridement: Sharp debridement of necrotic tissue under local anesthesia. Weekly in clinic until clean granulating base. 2) Cleaning: Normal saline irrigation. Avoid hydrogen peroxide and povidone-iodine on open wounds. 3) Dressing: Primary: Hydrogel for moist wound healing if dry. Alginate if exudative. Silver-based dressing if signs of infection. Secondary: Gauze and bandage, change daily or as saturated. 4) Offloading: Total contact cast (TCC) or removable walker boot. Non-negotiable for plantar ulcers. 5) Infection control: Wound culture and sensitivity. Empiric antibiotics: Amoxicillin-Clavulanate if mild infection. IV Piperacillin-Tazobactam if moderate-severe. 6) Glycemic control: Target fasting <130, post-meal <180. Insulin may be needed.', 'text', NULL, '2026-03-21 09:02:00'),
('msg-053', 'conv-009', 'user', 'Should I refer for vascular assessment?', 'text', NULL, '2026-03-21 09:15:00'),
('msg-054', 'conv-009', 'assistant', 'Yes, vascular assessment is essential for Ashok Pandey. Indications: 1) Wagner Grade 2 with potential vascular compromise 2) Age 56 with longstanding diabetes and peripheral neuropathy 3) Non-healing ulcer (if >4 weeks despite optimal care). Vascular assessment plan: Non-invasive: Ankle-Brachial Index (ABI) - values <0.9 suggest PAD, >1.3 may indicate calcified vessels. Toe pressures (more reliable in diabetics with calcified vessels) - healing unlikely if <30 mmHg. Duplex ultrasound of lower limb arteries. If ABI <0.9 or non-healing: CT Angiography of lower limb. Consider: Interventional referral for angioplasty if significant stenosis. Vascular surgeon consultation for bypass if multilevel disease. Under Ayushman Bharat: Vascular assessment and intervention covered under the diabetic foot management package (up to Rs 50,000 for Grade 2). Amputation prevention pathway should be activated if ABI <0.5.', 'text', NULL, '2026-03-21 09:17:00'),
('msg-055', 'conv-010', 'user', 'How do I configure automated claim status notifications in the system?', 'text', NULL, '2026-03-22 10:00:00'),
('msg-056', 'conv-010', 'assistant', 'To configure automated claim status notifications in AyushmanLife: Navigate to Settings > Notifications > Claim Alerts. Available notification triggers: 1) Claim submitted - notify submitter + assigned reviewer 2) Status change (any) - notify claim owner 3) Pre-authorization pending >48hrs - escalation alert 4) Claim rejected - notify claim owner + department head 5) Payment received - notify finance team + claim owner. Configuration steps: 1) Select trigger event from dropdown 2) Choose notification channels: Email, SMS, In-app, WhatsApp (requires WhatsApp Business API setup) 3) Set recipient roles (creator, reviewer, department head, finance) 4) Customize message template with variables: {claim_number}, {patient_name}, {status}, {amount} 5) Set escalation rules: e.g., if no action in 24hrs, escalate to next level. Save and test with a sample notification. Notifications are processed every 5 minutes by the background worker.', 'text', NULL, '2026-03-22 10:02:00'),
('msg-057', 'conv-011', 'user', 'Rajendra Prasad, 73M, COPD Stage 4 with cor pulmonale. He needs home oxygen therapy. What is the prescription protocol?', 'text', NULL, '2026-03-22 14:00:00'),
('msg-058', 'conv-011', 'assistant', 'Home Oxygen Therapy Prescription for Rajendra Prasad (73M, COPD GOLD Stage 4, Cor Pulmonale): Indications met: PaO2 <=55 mmHg or SpO2 <=88% at rest (GOLD Stage 4 with cor pulmonale qualifies). Prescription: Long-Term Oxygen Therapy (LTOT) >=15 hours/day (ideally >18 hrs for maximum survival benefit). Flow rate: Start at 1-2 L/min via nasal cannula. Titrate to target SpO2 88-92% (NOT >92% in COPD to avoid CO2 retention). ABG after 1 hour at set flow rate to confirm adequate PaO2 (>60 mmHg) without CO2 retention. Equipment options: 1) Oxygen concentrator (recommended for home use) - 5L capacity sufficient 2) Portable oxygen for mobility 3) Cylinder backup for power cuts. Monitoring: SpO2 home monitoring with pulse oximeter. ABG at 1 month, 3 months, then 6-monthly. Reassess oxygen needs with each exacerbation.', 'text', NULL, '2026-03-22 14:02:00'),
('msg-059', 'conv-011', 'user', 'Is home oxygen covered under ECHS?', 'text', NULL, '2026-03-22 14:15:00'),
('msg-060', 'conv-011', 'assistant', 'ECHS Home Oxygen Coverage for Rajendra Prasad: Yes, home oxygen is covered under ECHS with specific guidelines: 1) Oxygen concentrator: ECHS provides oxygen concentrators on loan basis for eligible patients. Application through ECHS polyclinic with specialist recommendation. 2) Oxygen cylinders: Refills covered when concentrator not feasible. 3) Documentation required: Specialist certificate confirming LTOT need, ABG reports showing PaO2 <=55 mmHg, Pulmonary function tests, ECHS prescription with specific flow rate and duration. 4) Approval process: Apply through Station HQ ECHS cell, medical board review may be required, approval typically within 2-4 weeks. 5) Consumables: Nasal cannulas, tubing, humidifier bottles covered. 6) Maintenance: Annual servicing of concentrator covered. Portable oxygen for travel may require separate approval. Ensure he has a letter for air travel if needed (supplemental O2 during flight).', 'text', '{"references": ["ECHS Policy on Domiciliary Equipment 2024"]}', '2026-03-22 14:17:00'),
('msg-061', 'conv-011', 'user', 'What about non-invasive ventilation at home?', 'text', NULL, '2026-03-22 14:25:00'),
('msg-062', 'conv-011', 'assistant', 'Home Non-Invasive Ventilation (NIV/BiPAP) for Rajendra Prasad: Indications in COPD Stage 4 with cor pulmonale: 1) Persistent hypercapnia (PaCO2 >52 mmHg) despite LTOT 2) Frequent hospitalizations with acute hypercapnic respiratory failure 3) Overlap syndrome (COPD + OSA) 4) Failure to wean from NIV during hospital admission. Prescription: Mode: BiPAP S/T (Spontaneous/Timed) IPAP: 12-20 cmH2O (start low, titrate) EPAP: 4-6 cmH2O Backup rate: 12-14 breaths/min Use: Minimum 5-6 hours/night, ideally during all sleep Duration: Long-term. Equipment: BiPAP machine with humidifier, appropriate mask (oronasal for mouth breathers), pulse oximeter. ECHS coverage: BiPAP machines can be provided on loan basis similar to oxygen concentrator. Requires specialist recommendation and medical board approval. The HOT-HMV trial showed 28% reduction in readmissions with home NIV in COPD patients.', 'text', '{"references": ["HOT-HMV Trial", "BTS NIV Guidelines"]}', '2026-03-22 14:27:00'),
('msg-063', 'conv-012', 'user', 'Surinder Kaur, 60F, mechanical mitral valve on Warfarin. Her INR today is 3.8. Target is 2.5-3.5. How should I adjust?', 'text', NULL, '2026-03-23 09:00:00'),
('msg-064', 'conv-012', 'assistant', 'Warfarin dose adjustment for Surinder Kaur (INR 3.8, target 2.5-3.5 for mechanical mitral valve): Current INR 3.8 is slightly above therapeutic range. Assessment: 1) Any bleeding symptoms? (check for bruising, gum bleeding, hematuria, melena) 2) Recent dietary changes (green leafy vegetables, alcohol) 3) New medications that interact with Warfarin 4) Recent illness (fever, diarrhea can increase INR). Dose adjustment if no bleeding: Reduce Warfarin dose by 10-15%. If current dose is 5mg daily, reduce to 4mg daily or alternate 5mg/4mg. Hold one dose today. Recheck INR in 3-5 days. If INR 3.5-4.5 with no bleeding: Reduce dose, no Vitamin K needed. If INR 4.5-10 with no bleeding: Hold 1-2 doses, consider low-dose oral Vitamin K (1-2.5mg). If INR >10 or any bleeding: Admit, IV Vitamin K 5-10mg, FFP/PCC if significant bleeding. For Surinder: Reduce dose, recheck in 4 days, counsel on consistent vitamin K intake.', 'text', NULL, '2026-03-23 09:02:00'),
('msg-065', 'conv-012', 'user', 'She mentions she ate a lot of papaya this week. Could that affect INR?', 'text', NULL, '2026-03-23 09:15:00'),
('msg-066', 'conv-012', 'assistant', 'Yes, papaya can significantly affect INR. Papaya contains papain, an enzyme that can potentiate Warfarin effect by: 1) Inhibiting platelet aggregation 2) Possible interaction with CYP2C9 enzyme metabolism. Case reports have documented INR increases of 1-3 units with regular papaya consumption. Evidence: Published case reports in British Journal of Clinical Pharmacology and Drug Safety journal. Action for Surinder: 1) Counsel to limit papaya intake to small, consistent amounts (not binge eating) 2) This is the likely cause of INR elevation from 3.2 to 3.8 3) Other fruits to be cautious with: mango (moderate effect), cranberry (well-documented interaction), pomegranate 4) Safe fruits: apple, banana, watermelon, guava. Dietary counseling: Maintain consistent vitamin K intake week to week. Green leafy vegetables can be eaten but in CONSISTENT amounts. Provide printed diet card for Warfarin patients. Follow-up INR after she resumes normal diet should normalize.', 'text', '{"references": ["Drug Safety Case Reports", "BJCP"]}', '2026-03-23 09:17:00'),
('msg-067', 'conv-013', 'user', 'Can you check my shift schedule for next week? I am Deepak Gupta from Cardiology nursing.', 'text', NULL, '2026-03-23 18:00:00'),
('msg-068', 'conv-013', 'assistant', 'I can help you check your schedule. Based on the AyushmanLife shift management system, here is your upcoming schedule for Deepak Gupta (Cardiology Nursing): Note: For the most accurate and updated schedule, please verify in the Workforce module under Shift Schedules. Your typical rotation appears to be the evening shift pattern. To view your complete schedule: 1) Go to Workforce > My Schedule 2) Select the date range for next week 3) You can also download your schedule as PDF. If you need to request a shift swap, use Workforce > Shift Swap Request and select the shift you want to exchange. The system will show available colleagues for swap. For any schedule concerns, contact Shift Supervisor or HR through the Service Desk.', 'text', NULL, '2026-03-23 18:02:00'),
('msg-069', 'conv-014', 'user', 'Tapan Mukherjee, 71M, atrial fibrillation. Currently on Warfarin. Should we switch to a DOAC?', 'text', NULL, '2026-03-24 10:00:00'),
('msg-070', 'conv-014', 'assistant', 'Assessment for switching Tapan Mukherjee (71M, AF, previous stroke 2024) from Warfarin to DOAC: CHA2DS2-VASc Score calculation: Age >=75: 2 points. Hypertension: likely 1 point. Stroke/TIA history: 2 points. Minimum score: 5 (very high stroke risk). Switching to DOAC - considerations: Arguments FOR switching: 1) DOACs have lower intracranial hemorrhage risk (50% reduction vs Warfarin) 2) No INR monitoring needed (reduces hospital visits for elderly) 3) Fewer food-drug interactions 4) Predictable pharmacokinetics. Arguments AGAINST: 1) Cost - DOACs are more expensive (Rs 40-80/day vs Warfarin Rs 2-3/day) 2) No reliable reversal agent for all DOACs in India (Idarucizumab for Dabigatran available, Andexanet not yet) 3) Renal function must be adequate (check CrCl) 4) Compliance crucial (no monitoring means non-compliance harder to detect). Recommended: If CrCl >30 and cost not a barrier, switch to Apixaban 5mg BD (best safety profile in elderly, ARISTOTLE trial).', 'text', '{"references": ["ARISTOTLE Trial", "ESC AF Guidelines 2024"]}', '2026-03-24 10:03:00'),
('msg-071', 'conv-014', 'user', 'His creatinine clearance is 45 ml/min. Is Apixaban safe?', 'text', NULL, '2026-03-24 10:15:00'),
('msg-072', 'conv-014', 'assistant', 'Yes, Apixaban is safe and actually the preferred DOAC at CrCl 45 ml/min. Dosing: Standard dose: Apixaban 5mg BD. Reduce to 2.5mg BD only if 2 of 3 criteria met: Age >=80 (he is 71 - no), Weight <=60 kg (check), Creatinine >=1.5 mg/dL (check). For Tapan at CrCl 45: Apixaban 5mg BD unless weight/creatinine criteria met. DOAC comparison at CrCl 45: 1) Apixaban 5mg BD - PREFERRED (safest in renal impairment, can be used down to CrCl 15) 2) Rivaroxaban 20mg OD - dose reduce to 15mg at CrCl 15-49 (borderline for him) 3) Dabigatran - less preferred, highest renal dependence (80% renal excretion) 4) Edoxaban 60mg OD - reduce to 30mg at CrCl 15-50. Monitoring on Apixaban: Renal function every 3-6 months (calculate months to next check = CrCl/10, so 45/10 = every 4.5 months). CBC annually. No routine coagulation monitoring needed.', 'text', NULL, '2026-03-24 10:17:00'),
('msg-073', 'conv-014', 'user', 'What about his CGHS coverage for DOACs?', 'text', NULL, '2026-03-24 10:30:00'),
('msg-074', 'conv-014', 'assistant', 'CGHS Coverage for DOACs (Tapan Mukherjee): Current CGHS DOAC policy: 1) Apixaban and Rivaroxaban are included in CGHS formulary 2) Available at CGHS wellness centers and empanelled hospitals 3) Requires specialist prescription (Cardiologist/Neurologist) with clear indication 4) Generic versions available and preferred under CGHS (significant cost saving). Cost comparison under CGHS: Warfarin (generic): Rs 2-3/day + INR monitoring costs. Apixaban (generic): Rs 25-40/day (Apigat, Apixawin brands). Apixaban (branded Eliquis): Rs 60-80/day. CGHS typically covers generic versions. Prescription requirement: CGHS specialist endorsement needed for DOAC initiation. Document: AF diagnosis, CHA2DS2-VASc score, reason for Warfarin switch (poor TTR, inconvenience, hemorrhagic risk). Include creatinine clearance in notes. Refill: Monthly prescription from CGHS dispensary. Can get 3-month supply with specialist authorization.', 'text', NULL, '2026-03-24 10:32:00'),
('msg-075', 'conv-014', 'user', 'Should we bridge with heparin during the switch?', 'text', NULL, '2026-03-24 10:40:00'),
('msg-076', 'conv-014', 'assistant', 'Bridging during Warfarin to DOAC switch for Tapan Mukherjee: No bridging with heparin is needed for a direct switch from Warfarin to Apixaban. Protocol: 1) Check current INR 2) If INR <2.0: Start Apixaban immediately 3) If INR 2.0-2.5: Start Apixaban immediately (same day as last Warfarin dose or next day) 4) If INR >2.5: Wait until INR drops to <2.5, then start Apixaban. Do NOT bridge with LMWH/heparin: The BRIDGE trial showed bridging anticoagulation increases bleeding risk 3-fold without reducing thrombotic events. Exception: Only consider bridging in mechanical heart valves (does not apply to Tapan who has AF, not mechanical valve). Practical steps: Day 1: Stop Warfarin, check INR. Day 2-3: Recheck INR if was >2.5. When INR <2.5: Start Apixaban 5mg BD. Counsel: No interruption gap - stroke risk is highest in first 48 hours without anticoagulation.', 'text', '{"references": ["BRIDGE Trial", "ACC Expert Consensus 2024"]}', '2026-03-24 10:42:00'),
('msg-077', 'conv-015', 'user', 'Kamala Rani, 69F, needs bilateral total knee replacement. What is the pre-operative assessment protocol?', 'text', NULL, '2026-03-25 09:00:00'),
('msg-078', 'conv-015', 'assistant', 'Pre-operative Assessment for Kamala Rani (69F, bilateral knee OA, DM) for Total Knee Replacement: Cardiac assessment: ECG (mandatory), 2D Echo if age >65 or cardiac symptoms, TMT if moderate-high cardiac risk. Clearance from cardiologist. Pulmonary: Chest X-ray, PFT if respiratory symptoms. SpO2 baseline. Laboratory: CBC, ESR, CRP, blood group and cross-match (arrange 2 units PRBC), RFT (creatinine, BUN, electrolytes), LFT, coagulation profile (PT/INR, aPTT), fasting glucose and HbA1c (target <8% pre-surgery, ideally <7.5%), urine routine and culture, Vitamin D level. Imaging: Weight-bearing AP and lateral X-rays both knees, long leg alignment films. Infection screening: Urine culture (must be sterile pre-op), dental clearance, nasal MRSA swab. Diabetes optimization: HbA1c must be <8% for elective surgery. Perioperative insulin protocol planning. Anesthesia: Pre-anesthetic checkup, discuss spinal vs general. DVT prophylaxis plan. Physiotherapy: Pre-hab exercises for 2-4 weeks before surgery to optimize outcomes.', 'text', NULL, '2026-03-25 09:02:00'),
('msg-079', 'conv-015', 'user', 'Her HbA1c is 8.5%. Should we postpone surgery?', 'text', NULL, '2026-03-25 09:15:00'),
('msg-080', 'conv-015', 'assistant', 'HbA1c 8.5% for Kamala Rani pre-TKR: Assessment: Most guidelines recommend HbA1c <8% (some centers use <8.5%) for elective joint replacement. At 8.5%, she is borderline. Recommendation: Postpone surgery by 6-8 weeks for glycemic optimization. Rationale: 1) HbA1c >8% increases surgical site infection risk by 2-3x in TKR 2) Periprosthetic joint infection is catastrophic and costly 3) Poor glycemic control impairs wound healing 4) 6-8 weeks is sufficient to reduce HbA1c by 1-1.5%. Optimization plan: Intensify insulin therapy (consider Basal-Bolus regimen), Endocrinology referral for rapid optimization, target fasting <130 and post-meal <180, add/optimize Empagliflozin for additional HbA1c reduction, dietary counseling by nutritionist, daily blood glucose monitoring. Recheck: HbA1c at 6 weeks. If <8%, proceed with surgery. If still >8% but trending down with good daily sugars, can consider proceeding with enhanced perioperative glucose monitoring protocol.', 'text', NULL, '2026-03-25 09:17:00'),
('msg-081', 'conv-016', 'user', 'What is the current NIS vaccination schedule for infants in India?', 'text', NULL, '2026-03-25 14:00:00'),
('msg-082', 'conv-016', 'assistant', 'National Immunization Schedule (NIS) India 2025-26 for Infants: Birth: BCG, OPV-0 (zero dose), Hepatitis B birth dose. 6 weeks: OPV-1, Pentavalent-1 (DPT+HepB+Hib), Rotavirus-1, fIPV-1, PCV-1. 10 weeks: OPV-2, Pentavalent-2, Rotavirus-2. 14 weeks: OPV-3, Pentavalent-3, Rotavirus-3, fIPV-2, PCV-2. 9 months: MR-1 (Measles-Rubella), Vitamin A 1st dose, PCV booster, JE-1 (in endemic districts). 16-24 months: DPT booster-1, OPV booster, MR-2, JE-2, Vitamin A 2nd dose. 5-6 years: DPT booster-2. 10 years: TT (Tetanus Toxoid). 16 years: TT booster. Additional vaccines (IAP recommended, not NIS): Typhoid conjugate vaccine at 9-12 months, Hepatitis A at 12 months, Varicella at 15 months, Influenza annually from 6 months. Catch-up schedules available for missed vaccines.', 'text', '{"references": ["MoHFW NIS 2025", "IAP Immunization Guidelines 2025"]}', '2026-03-25 14:02:00'),
('msg-083', 'conv-016', 'user', 'What about the new PCV schedule change?', 'text', NULL, '2026-03-25 14:10:00'),
('msg-084', 'conv-016', 'assistant', 'PCV (Pneumococcal Conjugate Vaccine) Schedule Update: Previous schedule: PCV at 6 weeks, 14 weeks, and 9 months (2+1 schedule). Current NIS (2025-26): PCV-1 at 6 weeks, PCV-2 at 14 weeks, PCV booster at 9 months. This is the 2p+1 schedule using PCV13 (Prevenar) or PCV10 (Synflorix). Key changes and notes: 1) Universal PCV was introduced in NIS in 2021 and now covers all states 2) PCV15 (Merck) approved in India - may replace PCV13 in future NIS updates 3) For high-risk infants (preterm, HIV-exposed, chronic lung disease): Consider 3+1 schedule (additional dose at 10 weeks) 4) Catch-up: If missed primary series, can give 2 doses 8 weeks apart after 12 months of age. IAP recommendation: PCV13 or PCV15 preferred over PCV10 for broader serotype coverage. If child received PCV10 primary series, can complete with PCV13/15 booster for additional coverage. Documentation: Record vaccine brand, batch number, and site of administration in immunization card.', 'text', '{"references": ["NIS 2025", "IAP PCV Advisory 2025"]}', '2026-03-25 14:12:00'),
('msg-085', 'conv-017', 'user', 'Jagdish Yadav is on twice-weekly hemodialysis via AV fistula. He is having inadequate clearance. What should I evaluate?', 'text', NULL, '2026-03-26 09:00:00'),
('msg-086', 'conv-017', 'assistant', 'Evaluation of Inadequate Dialysis Clearance for Jagdish Yadav (64M, ESRD, twice-weekly HD): Adequacy markers: Check Kt/V (target >1.2 per session for thrice-weekly, adjust for twice-weekly). URR (Urea Reduction Ratio) - target >65%. If below target, evaluate: 1) Access function: AV fistula flow rate (should be 600-1200 mL/min by ultrasound). Check for stenosis (physical exam: thrill, bruit quality). Venous pressure during dialysis (elevated suggests outflow stenosis). Recirculation test (should be <10%). 2) Prescription factors: Session duration (minimum 4 hours for twice-weekly). Blood flow rate (target 300-400 mL/min). Dialyzer size and membrane (consider high-flux upgrade). Dialysate flow rate (500-800 mL/min). 3) Patient factors: Interdialytic weight gain (excessive fluid gain dilutes clearance). Shortened sessions (patient leaving early). Needle placement issues. 4) Clinical: Serum albumin (malnutrition worsens outcomes), phosphorus control, hemoglobin level.', 'text', NULL, '2026-03-26 09:02:00'),
('msg-087', 'conv-017', 'user', 'His fistula flow is 400 mL/min. Is that concerning?', 'text', NULL, '2026-03-26 09:15:00'),
('msg-088', 'conv-017', 'assistant', 'Yes, AV fistula flow of 400 mL/min is below optimal and concerning. Normal fistula flow: 600-1200 mL/min for mature fistula. Flow <500 mL/min: Suggests developing stenosis and is a predictor of fistula failure. Evaluation needed: 1) Duplex ultrasound of fistula: Map entire circuit from arterial anastomosis to central veins. Look for: focal stenosis (>50% diameter reduction), calcification, aneurysm formation. 2) Physical examination: Weak thrill suggests inflow stenosis. Pulsatile fistula suggests outflow stenosis. Arm edema suggests central venous stenosis. 3) Dynamic venous pressure: Elevated >150 mmHg at 200 mL/min blood flow confirms outflow issue. Action plan: If stenosis confirmed: Referral for fistuloplasty (percutaneous angioplasty) - success rate 85-90%. If fistuloplasty fails: Surgical revision or new access creation. Timeline: Urgent referral within 1-2 weeks to prevent fistula thrombosis. Under AB-PMJAY: Fistuloplasty covered under vascular access procedures (package rate Rs 15,000-25,000).', 'text', '{"references": ["KDOQI Vascular Access Guidelines 2019"]}', '2026-03-26 09:17:00'),
('msg-089', 'conv-017', 'user', 'Should we consider increasing to thrice-weekly dialysis?', 'text', NULL, '2026-03-26 09:30:00'),
('msg-090', 'conv-017', 'assistant', 'Thrice-weekly dialysis for Jagdish Yadav: Clinical recommendation: Yes, thrice-weekly hemodialysis is the standard of care for ESRD and should be strongly considered. Evidence: 1) Twice-weekly HD has 1.3x higher mortality risk than thrice-weekly (DOPPS study) 2) Better volume control, lower interdialytic weight gain 3) Better phosphorus and potassium control 4) Reduced cardiovascular strain. Indications to switch to thrice-weekly: Inadequate Kt/V on twice-weekly despite optimization (his current situation). Residual kidney function declining (urine output <500 mL/day). Persistent hyperkalemia or fluid overload. Uncontrolled uremic symptoms. Barriers in Indian context: Patient travel and time commitment. Cost: Each session Rs 1,500-3,000 (under AB-PMJAY, 12 sessions/month covered). Caregiver burden. AB-PMJAY coverage: Hemodialysis package covers up to 12 sessions/month (thrice weekly). This is adequate for thrice-weekly schedule. Ensure re-authorization for the increased frequency.', 'text', NULL, '2026-03-26 09:32:00'),
('msg-091', 'conv-018', 'user', 'Fatima Begum has gestational diabetes at 30 weeks. Her fasting sugar is 105 and post-meal is 165. What management?', 'text', NULL, '2026-03-26 14:00:00'),
('msg-092', 'conv-018', 'assistant', 'Gestational Diabetes Management for Fatima Begum (35F, G2P1, 30 weeks, GDM): Current values: Fasting 105 mg/dL (target <95), Post-meal 165 mg/dL (target: 1-hr <140, 2-hr <120). Both above target, indicating need for intervention. Step 1 - Medical Nutrition Therapy (MNT): Total calories: 1800-2000 kcal/day (30 kcal/kg for normal BMI). Distribution: 40-50% carbohydrate, 20-25% protein, 25-30% fat. Small frequent meals: 3 main meals + 3 snacks. Bedtime snack important to prevent morning ketosis. Indian-specific: Replace white rice with brown rice/ragi, increase dal protein, avoid sweets/fruit juice. Step 2 - Exercise: 30 minutes walking after meals (reduces post-prandial glucose by 20-30 mg/dL). Step 3 - If not controlled in 1-2 weeks, start insulin: Fasting >95 despite MNT: Bedtime NPH insulin 4-6 units, titrate up by 2 units every 3 days. Post-meal >140 at 1-hr: Pre-meal rapid insulin (Aspart/Lispro) 4 units, titrate. Monitoring: Self-monitoring blood glucose 4 times daily (fasting + 3 post-meal).', 'text', NULL, '2026-03-26 14:02:00'),
('msg-093', 'conv-018', 'user', 'Can Metformin be used in pregnancy?', 'text', NULL, '2026-03-26 14:15:00'),
('msg-094', 'conv-018', 'assistant', 'Metformin use in pregnancy for GDM: Yes, Metformin can be used in pregnancy as an alternative to insulin. Evidence: MiG trial and multiple RCTs show Metformin is safe and effective in GDM. FOGSI (Federation of Obstetric and Gynecological Societies of India) guidelines 2024 include Metformin as second-line after MNT failure. Advantages: Oral administration (better compliance than insulin), weight neutral/slight reduction, lower hypoglycemia risk, significantly cheaper than insulin. Dosage: Start Metformin 500mg OD with dinner, increase to 500mg BD after 1 week, maximum 2500mg/day in divided doses. Limitations: 1) Crosses placenta (theoretical concern, no proven harm) 2) GI side effects (nausea, diarrhea) - worse in pregnancy 3) May need supplemental insulin in 25-40% of women (if glucose targets not met on maximum Metformin) 4) Not recommended if: eGFR <30, severe liver disease, fetal growth restriction suspected. For Fatima: Reasonable to start Metformin 500mg BD given her moderate hyperglycemia. Monitor for 2 weeks. If targets not met, add insulin rather than wait.', 'text', '{"references": ["MiG Trial", "FOGSI GDM Guidelines 2024"]}', '2026-03-26 14:17:00'),
('msg-095', 'conv-019', 'user', 'I need help coding a patient with diabetes, hypertension, and chronic kidney disease Stage 3. What ICD-10 codes should I use?', 'text', NULL, '2026-03-27 10:00:00'),
('msg-096', 'conv-019', 'assistant', 'ICD-10 Coding for Diabetes + Hypertension + CKD Stage 3: The coding depends on the documented relationship between conditions. Scenario 1: Diabetes causing CKD (most common): Primary: E11.22 - Type 2 DM with diabetic chronic kidney disease. Secondary: N18.3 - Chronic kidney disease, Stage 3 (must be coded additionally per ICD-10 convention). I12.9 - Hypertensive chronic kidney disease with CKD Stage 1-4. Scenario 2: Hypertension causing CKD: Primary: I12.9 - Hypertensive chronic kidney disease. Secondary: N18.3 - CKD Stage 3. E11.9 - Type 2 DM without complications. Scenario 3: Both diabetes and hypertension contributing to CKD: Primary: E11.22 - Type 2 DM with diabetic CKD. Secondary: I12.9 - Hypertensive CKD. N18.3 - CKD Stage 3. Key rules: 1) Always code N18.x as additional code with E11.22 or I12.9 2) ICD-10 assumes causal relationship between hypertension and CKD unless documented otherwise 3) Code all conditions that affect management. For AB-PMJAY claims, the primary diagnosis drives the package selection.', 'text', '{"references": ["ICD-10-CM Official Guidelines 2025", "WHO ICD-10"]}', '2026-03-27 10:02:00'),
('msg-097', 'conv-019', 'user', 'What about coding for diabetic foot ulcer with peripheral vascular disease?', 'text', NULL, '2026-03-27 10:15:00'),
('msg-098', 'conv-019', 'assistant', 'ICD-10 Coding for Diabetic Foot Ulcer with PVD: Code combination: Primary: E11.621 - Type 2 DM with foot ulcer. Additional codes: E11.51 - Type 2 DM with diabetic peripheral angiopathy without gangrene. L97.529 - Non-pressure chronic ulcer of other part of left foot with unspecified severity (specify laterality and severity). I70.249 - Atherosclerosis of native arteries of left leg with ulceration of unspecified site (if atherosclerosis documented). If gangrene present: E11.52 - Type 2 DM with diabetic peripheral angiopathy with gangrene. Coding tips: 1) Laterality matters (left/right) - always specify 2) Wagner grading maps to L97 severity: Grade 1 = limited to breakdown of skin, Grade 2 = fat layer exposed, Grade 3 = necrosis of muscle, Grade 4 = necrosis of bone 3) If osteomyelitis present: Add M86.x code 4) For AB-PMJAY, E11.621 as primary qualifies for diabetic foot management package (Rs 30,000-60,000 depending on intervention). Always document the causal relationship in the clinical notes for coding accuracy.', 'text', NULL, '2026-03-27 10:17:00'),
('msg-099', 'conv-019', 'user', 'And coding for COPD with acute exacerbation and pneumonia?', 'text', NULL, '2026-03-27 10:25:00'),
('msg-100', 'conv-019', 'assistant', 'ICD-10 Coding for COPD with Acute Exacerbation and Pneumonia: Code selection depends on documentation: If pneumonia is the cause of exacerbation: Primary: J44.0 - COPD with acute lower respiratory infection. Additional: Specify the pneumonia organism if known: J13 - Pneumonia due to Streptococcus pneumoniae. J15.1 - Pneumonia due to Pseudomonas. J18.9 - Pneumonia, unspecified (if organism unknown). If exacerbation and pneumonia are separate: Primary: J44.1 - COPD with acute exacerbation. Additional: J18.9 - Pneumonia, unspecified. Key coding rules: 1) J44.0 is used when the lower respiratory infection triggers the COPD exacerbation 2) Never code J44.0 and J44.1 together on same encounter 3) If on ventilator: Add Z99.11 (dependence on respirator) and 5A1935Z-5A1945Z (procedure codes) 4) Acute respiratory failure: Add J96.00 (acute, unspecified), J96.01 (with hypoxia), J96.02 (with hypercapnia). For AB-PMJAY: J44.0 or J44.1 as primary qualifies for COPD management package. If ventilator required, qualifies for ICU package (Rs 90,000-180,000 depending on duration).', 'text', '{"references": ["ICD-10-CM Coding Clinic", "AB-PMJAY Package Master"]}', '2026-03-27 10:27:00'),
('msg-101', 'conv-020', 'user', 'Meera Nambiar, 58F, CKD Stage 3b, hypertension uncontrolled on 3 drugs. Current: Amlodipine 10mg, Telmisartan 80mg, Chlorthalidone 12.5mg. BP today 158/96.', 'text', NULL, '2026-03-28 09:00:00'),
('msg-102', 'conv-020', 'assistant', 'Management of resistant hypertension in Meera Nambiar (58F, CKD 3b, on 3 antihypertensives): Current regimen assessment: Amlodipine 10mg (max dose CCB), Telmisartan 80mg (max dose ARB), Chlorthalidone 12.5mg (sub-optimal dose). BP target for CKD: <130/80 mmHg (KDIGO 2021). Current 158/96 is significantly above target. Step 1 - Optimize current medications: Increase Chlorthalidone to 25mg (more effective at this dose in CKD). Note: In CKD 3b (eGFR 30-44), loop diuretic may be more effective than thiazide. Consider switching Chlorthalidone to Furosemide 40mg BD or Torsemide 10mg OD. Step 2 - Add 4th agent: Spironolactone 25mg OD (most evidence for resistant hypertension, PATHWAY-2 trial). BUT: Caution in CKD 3b due to hyperkalemia risk. Monitor K+ at 1 week, then monthly. Hold if K+ >5.5. Step 3 - If Spironolactone contraindicated: Alpha-blocker: Prazosin 2.5mg BD or Doxazosin 2mg OD. Beta-blocker: Metoprolol 50mg BD (if heart rate >70). Step 4 - Evaluate secondary causes: Renal artery stenosis (Doppler ultrasound), primary aldosteronism (aldosterone/renin ratio), obstructive sleep apnea (STOP-BANG score).', 'text', '{"references": ["KDIGO BP Guidelines 2021", "PATHWAY-2 Trial"]}', '2026-03-28 09:02:00'),
('msg-103', 'conv-020', 'user', 'Her potassium is already 5.0. Can we still add Spironolactone?', 'text', NULL, '2026-03-28 09:15:00'),
('msg-104', 'conv-020', 'assistant', 'With K+ 5.0 in CKD 3b, Spironolactone requires careful consideration: Risk assessment: K+ 5.0 is at the upper limit of normal. Adding Spironolactone (which raises K+ by 0.3-0.5 mEq/L) could push to dangerous levels (>5.5). She is already on Telmisartan (ARB) which also increases K+. Options: Option A - Add Spironolactone with potassium mitigation: Start Spironolactone 12.5mg OD (half standard dose). Add Sodium Polystyrene Sulfonate (Kayexalate) PRN or Patiromer if available. Dietary K+ restriction (<2000mg/day). Switch Chlorthalidone to loop diuretic (increases K+ excretion). Monitor K+ at day 3, day 7, then weekly for 1 month. Stop if K+ >5.5. Option B (SAFER) - Avoid Spironolactone, use alternatives: Add Prazosin 2.5mg BD (alpha-blocker, no K+ effect). Consider Cilnidipine 10mg (dual-channel CCB, better than Amlodipine for proteinuria in CKD). Add Moxonidine 0.2mg OD (central sympatholytic). Recommendation: Option B is safer for Meera. Reserve Spironolactone trial only if Option B fails, with close monitoring.', 'text', NULL, '2026-03-28 09:17:00'),
('msg-105', 'conv-020', 'user', 'Good advice. Let us go with Prazosin. What starting dose and monitoring?', 'text', NULL, '2026-03-28 09:25:00'),
('msg-106', 'conv-020', 'assistant', 'Prazosin initiation for Meera Nambiar: Starting dose: Prazosin 0.5mg at bedtime (first-dose phenomenon - postural hypotension risk). First-dose precautions: Take first dose at bedtime lying down, warn about dizziness if getting up at night, keep hydrated. Titration: Day 1-3: 0.5mg at bedtime. Day 4-7: 1mg at bedtime (if tolerated). Week 2: 1mg BD (morning and bedtime). Week 3-4: 2.5mg BD (target dose). Maximum: 5mg BD (rarely needed). Monitoring schedule: Day 3: Phone call - ask about dizziness, orthostatic symptoms. Week 1: BP check (clinic or home monitoring). Week 2: BP check, assess orthostatic BP (lying and standing). Week 4: BP review, RFT, electrolytes. Monthly for 3 months, then quarterly. Home BP monitoring: Instruct patient to check BP twice daily (morning before meds, evening). Target <130/80. Maintain a BP diary. Side effects to watch: First-dose syncope, postural hypotension, headache, drowsiness, nasal congestion. If persistent hypotension, consider switching to Doxazosin (longer acting, once daily).', 'text', NULL, '2026-03-28 09:27:00'),
('msg-107', 'conv-020', 'user', 'Should we also optimize her loop diuretic?', 'text', NULL, '2026-03-28 09:30:00'),
('msg-108', 'conv-020', 'assistant', 'Yes, optimizing the diuretic is essential for Meera at CKD Stage 3b: Switch recommendation: Change Chlorthalidone 12.5mg to a loop diuretic. Rationale: In CKD 3b (eGFR 30-44), thiazides become less effective. Loop diuretics are preferred for both BP control and volume management. Options: 1) Torsemide 10mg OD (preferred): Longer duration of action (12-16 hrs vs 6 hrs for Furosemide), more predictable bioavailability (80% vs 50% for Furosemide), less rebound sodium retention, once daily dosing improves compliance. 2) Furosemide 40mg BD: More widely available and cheaper in India (Rs 1-2/tablet), but requires twice daily dosing. Recommendation: Start Torsemide 10mg OD in the morning. If BP/volume still uncontrolled after 2 weeks, increase to 20mg OD. Monitor: Weight daily (target: stable or slight reduction if edema), renal function and electrolytes at 1 week after switch, urine output should increase initially. Cost under ECHS: Both are covered. Generic Torsemide is Rs 3-5/tablet. Counsel about timing - take in morning to avoid nocturia.', 'text', NULL, '2026-03-28 09:32:00'),
('msg-109', 'conv-020', 'user', 'Perfect. Please summarize the updated medication plan.', 'text', NULL, '2026-03-28 09:35:00'),
('msg-110', 'conv-020', 'assistant', 'Updated Medication Plan for Meera Nambiar (58F, CKD 3b, Resistant Hypertension): CONTINUED (no change): 1) Amlodipine 10mg OD - morning 2) Telmisartan 80mg OD - morning. CHANGED: 3) Torsemide 10mg OD morning (replacing Chlorthalidone 12.5mg). NEW: 4) Prazosin - start 0.5mg at bedtime, titrate to 2.5mg BD over 3-4 weeks. Target BP: <130/80 mmHg. Monitoring timeline: Day 3: Phone call for Prazosin first-dose effects. Week 1: Serum creatinine, potassium, sodium (post diuretic switch). Week 2: Clinic BP, orthostatic BP, electrolytes. Week 4: Full review - BP, RFT, electrolytes, eGFR. Monthly x3 months, then quarterly. Home monitoring: BP diary twice daily, daily weight. Diet: Low salt (<2g sodium/day), low potassium (<2000mg/day), adequate protein (0.8g/kg/day). Follow-up appointment: 2 weeks for BP review. If BP still >140/90 at 4 weeks despite optimization, consider adding Moxonidine 0.2mg and secondary hypertension workup.', 'text', NULL, '2026-03-28 09:37:00'),
('msg-111', 'conv-001', 'user', 'One more question - what is the Ayushman Bharat package rate for diabetes management with complications?', 'text', NULL, '2026-03-15 09:25:00'),
('msg-112', 'conv-002', 'assistant', 'I have also prepared a detailed discharge plan and follow-up schedule for Suresh Babu. The ECHS pre-authorization for cardiac MRI has been submitted. Expected approval in 5-7 days. Meanwhile, start optimizing his heart failure medications as discussed.', 'text', NULL, '2026-03-16 10:40:00'),
('msg-113', 'conv-003', 'user', 'Thanks. Can you also generate a medication reconciliation report for Arun Krishnan?', 'text', NULL, '2026-03-17 11:30:00'),
('msg-114', 'conv-005', 'assistant', 'I have prepared a detailed diet chart for Savitri Mishra in Hindi that she can take home. It includes weekly meal plans with potassium content calculated for each meal. Also included is a list of safe fruits and vegetables for CKD patients.', 'text', NULL, '2026-03-18 14:35:00'),
('msg-115', 'conv-006', 'user', 'Great, let me set up the cardiac rehab program for him. Can the system generate the exercise prescription form?', 'text', NULL, '2026-03-19 09:45:00'),
('msg-116', 'conv-008', 'assistant', 'Summary for Rekha Choudhary: I have documented the follow-up protocol in her patient record, set up automated reminders for her next mammogram and Tamoxifen monitoring bloodwork, and flagged her AB-PMJAY coverage for annual renewal check. The hot flash management plan has been added to her medication notes.', 'text', NULL, '2026-03-20 10:45:00'),
